const row = $input.first().json;

if (!row.found) {
  return [{ json: { error: 'manufacturer not found', slug: row.input_slug } }];
}

const entityTypeFilter = $('Manufacturer Webhook').first().json.query?.entity_type || '';

const products = {};
let total = 0;
for (const p of (row.products || [])) {
  if (entityTypeFilter && p.entity_type !== entityTypeFilter) continue;
  if (!products[p.entity_type]) products[p.entity_type] = [];
  products[p.entity_type].push({ slug: p.slug, name: p.name, category: p.category });
  total++;
}

return [{ json: { slug: row.mfr_slug, canonical_name: row.canonical_name, products, total } }];
